		nodeInfo {
			id
		}
		projects {
			edges {
				node {
					id
				}
			}
		}
	}
`;

interface ShellRouteDefaultsResult {
	nodeInfo: {
		id: string;
	};
	projects: {
		edges: Array<{
			node: {
				id: string;
			};
		}>;
	};
}

export type ProjectShellSection =
	| 'beads'
	| 'documents'
	| 'graph'
	| 'sessions'
	| 'personas'
	| 'plugins';

export async function resolveDefaultProjectRoute(
	section: ProjectShellSection,
	fetchFn: typeof globalThis.fetch
): Promise<string> {
	const client = createClient(fetchFn);
	const data = await client.request<ShellRouteDefaultsResult>(SHELL_ROUTE_DEFAULTS_QUERY);
	const nodeId = data.nodeInfo.id;
	const projectId = data.projects.edges[0]?.node.id;

	if (!projectId) {
		return `/nodes/${nodeId}`;
	}

	return `/nodes/${nodeId}/projects/${projectId}/${section}`;
}

import type { LayoutLoad } from './$types';
import { gql } from 'graphql-request';
import { error } from '@sveltejs/kit';
import { createClient } from '$lib/gql/client';
import { projectStore } from '$lib/stores/project.svelte';

const PROJECTS_QUERY = gql`
	query ProjectsForLayout {
		projects {
			edges {
				node {
					id
					name
					path
				}
			}
		}
	}
`;

interface ProjectNode {
	id: string;
	name: string;
	path: string;
}

interface ProjectsResult {
	projects: {
		edges: Array<{ node: ProjectNode }>;
	};
}

// Hydrate projectStore from params.projectId on every navigation into this
// route subtree so deep-links and page reloads see a populated store. Without
// this, the sidebar at NavShell.svelte disables every link because
// projectStore.value is null — only ProjectPicker.onchange would set it.
export const load: LayoutLoad = async ({ params, fetch }) => {
	const client = createClient(fetch as unknown as typeof globalThis.fetch);
	const data = await client.request<ProjectsResult>(PROJECTS_QUERY);
	const project = data.projects.edges
		.map((e) => e.node)
		.find((p) => p.id === params.projectId);
	if (!project) {
		throw error(404, `project ${params.projectId} not found`);
	}
	projectStore.set(project);
	return { project };
};

import { expect, test } from '@playwright/test';

// Fixtures used across tests
const NODE_INFO = { id: 'node-abc', name: 'Test Node' };
const PROJECTS = [
	{ id: 'proj-1', name: 'Project Alpha', path: '/repos/alpha' },
	{ id: 'proj-2', name: 'Project Beta', path: '/repos/beta' }
];

/**
 * Intercept /graphql and respond with mock data based on query type.
 */
async function mockGraphQL(
	page: import('@playwright/test').Page,
	nodeInfo = NODE_INFO,
	projects = PROJECTS
) {
	await page.route('/graphql', async (route) => {
		const body = route.request().postDataJSON() as { query: string };
		if (body.query.includes('NodeInfo')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({ data: { nodeInfo } })
			});
		} else if (body.query.includes('Projects')) {
			await route.fulfill({
				status: 200,
				contentType: 'application/json',
				body: JSON.stringify({
					data: { projects: { edges: projects.map((p) => ({ node: p })) } }
				})
			});
		} else {
			await route.continue();
		}
	});
}

